func TestCollectBurnout_NoWarnings(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	config := DefaultBurnoutConfig()

	// Test case: Normal work day (no warnings)
	screen := ScreenResult{
		ScreenOnMinutes: 360, // 6 hours
